oxy_webhelp_navlinks = {"azr_sql_mi_nw_configs-d30753e20882":{"topics":[{"title":"Configuring a private endpoint for Azure SQL MI","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> uses your Exocompute instance to connect to the source Azure SQL         MI that you are protecting with <span class=\"ph\">RSC<\/span>, take Rubrik backups, and upload those         backups to Azure storage. For enhanced security and improved performance, configure a         private endpoint for this connection.<\/p>","href":"saas\/azr_sql_mi_configuring_pvt_endpoint.html","attributes":{"data-id":"azr_sql_mi_configuring_pvt_endpoint"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_configuring_pvt_endpoint-d30753e20896","topics":[]},{"title":"Configuring VNet peering for Azure SQL MI","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> uses the Exocompute instance to connect to the source Azure SQL         MI, take Rubrik backups, and upload those backups to Azure storage. For a cost-effective         method of enabling this connection, configure VNet peering by peering the Exocompute VNet         with the SQL MI VNet and adding the required network security group rules.<\/p>","href":"saas\/azr_sql_mi_configuring_srvc_endpoint.html","attributes":{"data-id":"azr_sql_mi_configuring_srvc_endpoint"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_configuring_srvc_endpoint-d30753e20912","topics":[]}]}};